INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (137, "界雷", 2017, "魔法攻撃のダメージが小アップし、物理攻撃を行うキャラが行動する度にそのキャラの最大ＨＰに応じて最大99999の割合ダメージを与える。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (146, "百花繚乱", 2017, "一定時間が経過するごとに、敵、味方全体のＴＰを中回復させる。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (147, "炎天烈日", 2017, "一定時間が経過するごとに、敵、味方全体に最大ＨＰに応じた最大20万の割合ダメージを与える。さらに、付与される継続ダメージが上昇する。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (148, "秋高馬肥", 2017, "一定時間が経過するごとに、敵、味方全体の物理攻撃力、魔法攻撃力、物理防御力、魔法防御力をアップさせる。この効果の効果量は敵、味方を合わせた数に応じて増加する。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (149, "寒気凛冽", 2017, "敵、味方全体の行動速度を小ダウンさせる。このスキルの効果は他の行動速度変化スキルと重複する。さらに一定時間が経過するごとに、初期値より行動速度が低い状態のキャラに凍結状態を付与する。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (162, "妨魔塵", 2017, "魔法攻撃のダメージが小ダウンする。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (164, "雷雲", 2017, "一定時間が経過するごとに、敵全体に最大ＨＰに応じた魔法割合ダメージを与える。さらに、キャラのＨＰが50％未満の場合、麻痺状態を付与する。この効果によるダメージでは、ＴＰが回復しない。この効果の状態異常はダメージを無効化しても付与される。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (169, "暴風", 2017, "一定時間が経過するごとに、敵全体をノックバックさせる。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (170, "豪雨", 2017, "一定時間が経過するごとに、敵全体の行動速度をバトル終了まで小ダウンさせる。さらに、物理攻撃力と魔法攻撃力をバトル終了まで小ダウンさせる。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (175, "絶氷", 2017, "物理攻撃クリティカル時のダメージが小アップする。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (186, "雷雲", 2017, "一定時間が経過するごとに、敵全体に最大ＨＰに応じた魔法割合ダメージを与える。この効果によるダメージでは、ＴＰが回復しない。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (207, "忌火", 2017, "継続ダメージを与える状態異常のダメージの発生間隔と効果時間が延長される。");
INSERT INTO `v1_b34afb1244b342a70f9fb768eede87bfc6dfa7f6814f70f42a31c41edcc2c171` VALUES (228, "マナの流脈", 2017, "一定時間が経過するごとに、敵、味方全体の物理攻撃力、魔法攻撃力をアップさせる。この効果の効果量は現在の対象の物理攻撃力、魔法攻撃力に応じて増加する。");
